import { makeStyles, Tooltip, withStyles, Typography } from "@material-ui/core"
import React from "react"

import skillList from "../../datasheet/skill_list.yml"

import iconlist from "./skill_icons"
import Block from "./block"

const useStyle = makeStyles(theme => {
  return {
    skill: {
      display: "flex",
      alignItems: "center",
      justifyContent: "center",
      // background: '#3331',
      whiteSpace: "nowrap",
      "& > img": {
        margin: 0,
        marginRight: "0.5rem",
        height: "1.2rem",
        width: "1.6rem",
        userSelect: "none",
        userDrag: "none",
      },
      marginRight: "1rem",
      marginTop: "0.5rem",
      fontWeight: "900",
      fontSize: "0.8rem",
      fontStyle: "italic",
      color: "#22254f",
      // border: 'solid 0.08rem #3331',
      padding: "0px 0.3rem",
      "@media screen and (max-width: 480px)": {
        flexDirection: "column",
        whiteSpace: "wrap",
        "& > img": {
          marginRight: "0",
        },
        marginLeft: "0.5rem",
        marginRight: "0.5rem",
        fontSize: "0",
      },
    },
    skillBlock: {
      flexWrap: "wrap",
      display: "inline-flex",
    },
    skillTitle: {
      fontSize: "0.7rem",
      marginBottom: 0,
      fontWeight: "100",
      color: "#9f9a9c",
    },
    genreBlock: {
      marginBottom: ".4rem",
      "@media (max-width: 599px)": {
        marginLeft: "1rem",
      },
      "@media (max-width: 480px)": {
        textAlign: "center",
        marginLeft: 0,
      },
    },
    skillSet: {
      paddingLeft: "2rem",
      "@media (max-width: 959px)": {
        paddingLeft: 0,
        margin: "0 auto",
      },
    },
  }
})

const SkillTooltip = withStyles(theme => {
  return {
    tooltip: {
      background: "#fbf8f4",
      color: "#22254f",
      borderRadius: 0,
      boxShadow: "0 0 1rem #3332",
      padding: theme.spacing(2),
    },
  }
})(Tooltip)

const SkillTooltipTitle = ({ skill }) => {
  return (
    <>
      <Typography variant="h6">{skill.name}</Typography>
      {skill.desc && <Typography variant="caption">{skill.desc}</Typography>}
    </>
  )
}

const SkillBasic = ({ skill, cls, svg }) => {
  return (
    <SkillTooltip
      title={<SkillTooltipTitle skill={skill} />}
      enterTouchDelay={50}
      interactive
    >
      <div className={cls}>
        <img src={iconlist[svg]} alt={svg} />
        {skill.name}
      </div>
    </SkillTooltip>
  )
}

const Skill = ({ data }) => {
  // const data = skillList[0]
  const { category, subskills } = data
  const classes = useStyle()
  return (
    <div className={classes.genreBlock}>
      <h3 className={classes.skillTitle}>{category}</h3>
      <div className={classes.skillBlock}>
        {subskills.map(skill => {
          return (
            <SkillBasic
              key={skill.name}
              skill={skill}
              cls={classes.skill}
              svg={skill.svg}
            >
              {skill.name}
            </SkillBasic>
          )
        })}
      </div>
    </div>
  )
}

export default () => (
  <Block title="個人技能">
    {skillList.map(data => {
      return <Skill data={data} key={data.category} />
    })}
  </Block>
)
