import React, { useEffect, useState } from "react"
import { graphql } from "gatsby"

import SEO from "../components/seo"
import {
  Box,
  Container,
  CssBaseline,
  Divider,
  Grid,
  makeStyles,
} from "@material-ui/core"

import clsx from "clsx"

import Block from "../components/homepage/block"
import Lake from "../components/homepage/lake"
import Sider from "../components/homepage/sider"
import Skill from "../components/homepage/skill"
import waveline from "../svg/wave.svg"

import Gallery from "../components/homepage/gallery"
import SocialBlock from "../components/social-media"
import RelativeProject from "../components/homepage/relative-link"
import WaveDiv from "../components/homepage/wave-divider"
import ErrorBoundary from "../components/ErrorBoundary"

// import ShowModels from '../components/model'
import loadable from "@loadable/component"
import { Helmet } from "react-helmet"

const waveBorderCss = require("!css-loader!../css/waveborder.css").toString()

const ShowModels = loadable(() => import("../components/homepage/model"), {
  ssr: false,
})

const useStyle = makeStyles(theme => {
  return {
    root: {
      background: "#f9f6f2",
      // backgroundImage: 'url(./BG/paper001_3K_Color.jpg)',
      // backgroundRepeat: 'repeat',
      // backgroundSize: '1400px 700px',
      minHeight: "100vh",
    },
    leftHeader: {
      display: "flex",
      alignItems: "center",
      justifyContent: "center",
      // position: 'relative',
      "@media (min-width: 960px)": {
        maxHeight: "100vh",
        top: 0,
        position: "sticky",
      },
    },
    leftSider: {
      marginTop: "6rem",
      marginBottom: "6rem",
      display: "block",
      width: "max(30%,7rem)",
      // margin: '20px'
      // background: 'green',
    },
    waveDiv: {
      backgroundColor: "transparent",
      backgroundImage: `url(${waveline})`,
      backgroundSize: "10px",
      backgroundRepeat: "repeat-y",
      padding: "0px 5px",
      margin: "5rem 0rem 5rem auto",
      position: "absolute",
      height: "calc(100vh - 10rem)",
      right: 10,
      "@media (max-width: 960px)": {
        display: "none",
      },
    },

    rightBlock: {
      "@media (min-width: 959px)": {
        padding: "3rem",
      },
      paddingBottom: "5rem",
    },
  }
})

const IndexPage = () => {
  const classes = useStyle()
  const [pageReady, setPageReady] = useState(false)
  useEffect(() => {
    setPageReady(true)
    document.body.style.backgroundColor = "#f9f6f2"
  }, [])
  return (
    <>
      <CssBaseline />
      <SEO title="Landing Page" />
      <Helmet>
        <style>{waveBorderCss}</style>
      </Helmet>
      <Container maxWidth="xl" className={classes.root} disableGutters>
        <Grid container style={{ minHeight: "100vh" }}>
          <Grid item xs={12} md={3} lg={2} className={classes.leftHeader}>
            <Box className={clsx(classes.leftSider)}>
              <Sider />
            </Box>
            <Divider
              orientation="vertical"
              className={classes.waveDiv}
              flexItem
            />
          </Grid>
          <Grid item xs={12} md={9} lg={10} className={classes.rightBlock}>
            <Box py={6}>
              <Lake />
            </Box>
            <Grid container>
              <Grid item md={12} lg={6} xl={5} zeroMinWidth>
                <Block />
              </Grid>
              <Grid item md={12} lg={6} xl={7} zeroMinWidth>
                <Skill />
              </Grid>
            </Grid>
            <Box py={6}>
              <Block title="畫廊展示">
                <Gallery />
              </Block>
            </Box>
            <Block title="建置專案">
              <RelativeProject />
            </Block>
            {pageReady && (
              <Block title="三維建模">
                <ErrorBoundary>
                  <ShowModels />
                </ErrorBoundary>
              </Block>
            )}
            <WaveDiv />
            <SocialBlock />
          </Grid>
        </Grid>
      </Container>
    </>
  )
}

export const query = graphql`
  query HomePageQuery {
    site {
      siteMetadata {
        description
      }
    }
  }
`

export default IndexPage
