import React, { useState } from "react"
import { useStaticQuery, graphql } from "gatsby"
import Img from "gatsby-image"
import { Swiper, SwiperSlide } from "swiper/react"
import swiperCss from "!raw-loader!sass-loader!swiper/swiper.scss"
import {
  Box,
  IconButton,
  Tooltip,
  Typography,
  withStyles,
} from "@material-ui/core"

import NavigateNextIcon from "@material-ui/icons/NavigateNext"
import NavigateBeforeIcon from "@material-ui/icons/NavigateBefore"

import desc from "../../datasheet/showcase.yml"
import { Helmet } from "react-helmet"
// import "../../css/waveborder.css"

const getTooltip = key => {
  if (desc[key]) {
    return (
      <>
        <Typography variant="h6">{desc[key].title}</Typography>
        {desc[key].text && (
          <Typography variant="caption">{desc[key].text}</Typography>
        )}
      </>
    )
  } else {
    return <Typography variant="caption">{key.replace(".jpg", "")}</Typography>
  }
}

const GalleryTooptip = withStyles(theme => {
  return {
    tooltip: {
      background: "#fbf8f4",
      color: "#22254f",
      borderRadius: 0,
      boxShadow: "0 0 1rem #3332",
      padding: theme.spacing(2),
    },
  }
})(Tooltip)

const Navigator = withStyles(theme => {
  return {
    root: {
      color: "white",
      borderRadius: 0,
      "&:hover": {
        backgroundColor: "#3333",
        "@media (hover: none)": {
          backgroundColor: "transparent",
        },
      },
    },
  }
})(IconButton)

const Gallery = () => {
  const [swiper, setSwiper] = useState()
  const data = useStaticQuery(graphql`
    query {
      showcases: allFile(filter: { relativePath: { regex: "/showcase/" } }) {
        nodes {
          childImageSharp {
            fixed(height: 250, quality: 80) {
              ...GatsbyImageSharpFixed_withWebp
              originalName
            }
          }
        }
      }
    }
  `)
  if (!data?.showcases?.nodes) {
    return <div>Gallery not found</div>
    // return <SwiperSlide style={{ width: 200 }}></SwiperSlide>
  } else if (!data.showcases.nodes[0]?.childImageSharp?.fixed) {
    return <div>Gallery not found</div>
  }

  return (
    <Box position="relative">
      <Helmet>
        <style>{swiperCss}</style>
      </Helmet>
      <Swiper
        spaceBetween={50}
        slidesPerView={"auto"}
        loop
        loopedSlides={data.showcases.nodes.length}
        grabCursor
        roundLengths
        onSwiper={swp => setSwiper(swp)}
      >
        {data.showcases.nodes.map(({ childImageSharp }) => {
          const fixed = childImageSharp.fixed
          return (
            <SwiperSlide
              style={{ width: fixed.width }}
              key={fixed.originalName}
            >
              <GalleryTooptip
                title={getTooltip(fixed.originalName)}
                placement="top"
                interactive
                enterTouchDelay={150}
              >
                <div style={{ height: "250px" }} className="wave-border">
                  <Img fixed={fixed} />
                </div>
              </GalleryTooptip>
            </SwiperSlide>
          )
        })}
      </Swiper>
      <Box
        display="flex"
        height="100%"
        position="absolute"
        top="0"
        left="0"
        zIndex="100"
      >
        <Navigator
          onClick={e => swiper.slidePrev()}
          children={<NavigateBeforeIcon />}
          aria-label="slide to previous slide"
        />
      </Box>
      <Box
        display="flex"
        height="100%"
        position="absolute"
        top="0"
        right="0"
        zIndex="100"
      >
        <Navigator
          onClick={e => swiper.slideNext()}
          children={<NavigateNextIcon />}
          aria-label="slide to next slide"
        />
      </Box>
    </Box>
  )
}

export default Gallery
