import {
  Card,
  CardActionArea,
  CardContent,
  Grid,
  Typography,
  withStyles,
} from "@material-ui/core"
import { useStaticQuery, withPrefix, graphql } from "gatsby"
import React from "react"
import Img from "gatsby-image"
import { find, map } from "lodash"
import pages from '../../datasheet/relative-pages.yml'
// import "../../css/waveborder.css"

const RCard = withStyles(theme => {
  return {
    root: {
      display: "inline-flex",
      verticalAlign: "top",
      background: "#f9f6f2",
      color: "#8a446b",
      borderRadius: "10px",
      border: "none",
      // maxWidth: 425,
      // marginRight: theme.spacing(2),
      // marginBottom: theme.spacing(2),
    },
  }
})(Card)

const RCardActionArea = withStyles(theme => {
  return {
    root: {
      // border: 'solid 0.05rem #ccd6d5',
      borderRadius: "10px",
      padding: theme.spacing(0.5),
    },
  }
})(CardActionArea)

const Relative = ({ image, href, title = "Relative", desc = "" }) => {
  return (
    <Grid item sm={12} lg={6} xl={4}>
      <RCard variant="outlined">
        <RCardActionArea component="a" href={href} rel="noopener">
          {image}
          {/* <Divider></Divider> */}
          <CardContent>
            <Typography gutterBottom variant="h6" component="h2">
              {title}
            </Typography>
            <Typography variant="body2" color="textSecondary" component="p">
              {desc}
            </Typography>
          </CardContent>
        </RCardActionArea>
      </RCard>
    </Grid>
  )
}

export default () => {
  const data = useStaticQuery(graphql`
    query {
      relative: allFile(filter: { relativePath: { regex: "/relative/" } }) {
        nodes {
          name
          childImageSharp {
            fluid(maxWidth: 480, quality: 75) {
              ...GatsbyImageSharpFluid_withWebp
            }
          }
        }
      }
    }
  `)
  const pagesData = map(pages, (({ href, prefix, image, desc }, title) => {
    return {
      title,
      desc,
      fluid: find(data?.relative?.nodes, { name: image })?.childImageSharp?.fluid,
      href: prefix ? withPrefix(href) : href,
    }
  }))
  return (
    <Grid container spacing={2}>
      {
        pagesData.map(({ fluid, ...rest }) => {
          return <Relative
            image={
              fluid && <Img fluid={fluid} className="wave-border" />
            }
            key={rest.title}
            {...rest}
          />
        })
      }
    </Grid>
  )
}
